class MainActivity : AppCompatActivity() {

    companion object {
        private const val TAG = "WebViewWrapper"
        private const val WEB_APP_URL = "file:///android_asset/index.html" // or your remote URL
        private const val NOTIFICATION_CHANNEL_ID = "web_app_notifications"
        private const val NOTIFICATION_CHANNEL_NAME = "Web App Notifications"
        private const val PREFS_NAME = "WebAppLocalStorage"
    }

    private lateinit var webView: WebView
    private lateinit var sharedPreferences: SharedPreferences

    // Camera related
    private var cameraPhotoUri: Uri? = null
    private var fileUploadCallback: ValueCallback<Array<Uri>>? = null

    // Activity result launchers
    private lateinit var cameraPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var notificationPermissionLauncher: ActivityResultLauncher<String>
    private lateinit var cameraCaptureLauncher: ActivityResultLauncher<Uri>
    private lateinit var fileChooserLauncher: ActivityResultLauncher<Intent>

    // Callback tracking for bridge calls
    private var pendingCameraCallback: String? = null

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        setupActivityResultLaunchers()
        createNotificationChannel()
        setupWebView()
    }

    private fun setupActivityResultLaunchers() {
        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            if (isGranted) {
                launchCamera()
            } else {
                sendCallbackToWeb(pendingCameraCallback, "error", "Camera permission denied")
            }
        }

        notificationPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            val status = if (isGranted) "granted" else "denied"
            webView.post {
                webView.evaluateJavascript(
                    "javascript:window.onNotificationPermissionResult && window.onNotificationPermissionResult('$status')",
                    null
                )
            }
        }

        cameraCaptureLauncher = registerForActivityResult(
            ActivityResultContracts.TakePicture()
        ) { success ->
            if (success && cameraPhotoUri != null) {
                val base64Image = uriToBase64(cameraPhotoUri!!)
                sendCallbackToWeb(pendingCameraCallback, "success", base64Image ?: "")
            } else {
                sendCallbackToWeb(pendingCameraCallback, "error", "Camera capture cancelled")
            }
        }

        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.StartActivityForResult()
        ) { result ->
            if (result.resultCode == Activity.RESULT_OK) {
                val data = result.data
                val results = if (data?.clipData != null) {
                    val count = data.clipData!!.itemCount
                    Array(count) { i -> data.clipData!!.getItemAt(i).uri }
                } else if (data?.data != null) {
                    arrayOf(data.data!!)
                } else if (cameraPhotoUri != null) {
                    arrayOf(cameraPhotoUri!!)
                } else {
                    null
                }
                fileUploadCallback?.onReceiveValue(results ?: arrayOf())
            } else {
                fileUploadCallback?.onReceiveValue(null)
            }
            fileUploadCallback = null
        }
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun setupWebView() {
        webView = findViewById(R.id.webView)

        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            mediaPlaybackRequiresUserGesture = false
            mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
            cacheMode = WebSettings.LOAD_DEFAULT
            databaseEnabled = true
            setSupportZoom(true)
            builtInZoomControls = true
            displayZoomControls = false
            useWideViewPort = true
            loadWithOverviewMode = true
            javaScriptCanOpenWindowsAutomatically = true
        }

        // Add JavaScript bridge interface
        webView.addJavascriptInterface(NativeBridge(this), "NativeBridge")

        webView.webViewClient = AppWebViewClient()
        webView.webChromeClient = AppWebChromeClient()

        webView.loadUrl(WEB_APP_URL)
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                NOTIFICATION_CHANNEL_NAME,
                NotificationManager.IMPORTANCE_DEFAULT
            ).apply {
                description = "Notifications from the web app"
            }
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

