    inner class NativeBridge(private val activity: MainActivity) {

        // ---- Camera Functions ----

        @JavascriptInterface
        fun openCamera(callbackName: String?) {
            activity.runOnUiThread {
                pendingCameraCallback = callbackName
                if (ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA)
                    == PackageManager.PERMISSION_GRANTED
                ) {
                    launchCamera()
                } else {
                    cameraPermissionLauncher.launch(Manifest.permission.CAMERA)
                }
            }
        }

        @JavascriptInterface
        fun isCameraAvailable(): Boolean {
            return activity.packageManager.hasSystemFeature(PackageManager.FEATURE_CAMERA_ANY)
        }

        @JavascriptInterface
        fun hasCameraPermission(): Boolean {
            return ContextCompat.checkSelfPermission(activity, Manifest.permission.CAMERA) ==
                    PackageManager.PERMISSION_GRANTED
        }

        // ---- Local Storage Functions ----

        @JavascriptInterface
        fun setItem(key: String, value: String) {
            sharedPreferences.edit().putString(key, value).apply()
        }

        @JavascriptInterface
        fun getItem(key: String): String? {
            return sharedPreferences.getString(key, null)
        }

        @JavascriptInterface
        fun removeItem(key: String) {
            sharedPreferences.edit().remove(key).apply()
        }

        @JavascriptInterface
        fun clear() {
            sharedPreferences.edit().clear().apply()
        }

        @JavascriptInterface
        fun getAllKeys(): String {
            val keys = sharedPreferences.all.keys
            val jsonArray = org.json.JSONArray(keys.toList())
            return jsonArray.toString()
        }

        @JavascriptInterface
        fun setSecureItem(key: String, value: String) {
            // In production, use EncryptedSharedPreferences
            val encodedValue = Base64.encodeToString(value.toByteArray(), Base64.DEFAULT)
            sharedPreferences.edit().putString("secure_$key", encodedValue).apply()
        }

        @JavascriptInterface
        fun getSecureItem(key: String): String? {
            val encodedValue = sharedPreferences.getString("secure_$key", null) ?: return null
            return String(Base64.decode(encodedValue, Base64.DEFAULT))
        }

